 9884   LLVM_DEBUG(dbgs() << Str);
 9885   if (ViewSLPTree)
 9886     ViewGraph(this, "SLP" + F->getName(), false, Str);
 9887 #endif
 9888 
 9889   return Cost;
 9890 }
