 9892 /// Tries to find extractelement instructions with constant indices from fixed
 9893 /// vector type and gather such instructions into a bunch, which highly likely
 9894 /// might be detected as a shuffle of 1 or 2 input vectors. If this attempt was
 9895 /// successful, the matched scalars are replaced by poison values in \p VL for
 9896 /// future analysis.
 9897 std::optional<TTI::ShuffleKind>
 9898 BoUpSLP::tryToGatherSingleRegisterExtractElements(
 9899     MutableArrayRef<Value *> VL, SmallVectorImpl<int> &Mask) const {
 9900   // Scan list of gathered scalars for extractelements that can be represented
 9901   // as shuffles.
 9902   MapVector<Value *, SmallVector<int>> VectorOpToIdx;
 9903   SmallVector<int> UndefVectorExtracts;
 9904   for (int I = 0, E = VL.size(); I < E; ++I) {
 9905     auto *EI = dyn_cast<ExtractElementInst>(VL[I]);
 9906     if (!EI) {
 9907       if (isa<UndefValue>(VL[I]))
 9908         UndefVectorExtracts.push_back(I);
 9909       continue;
 9910     }
 9911     auto *VecTy = dyn_cast<FixedVectorType>(EI->getVectorOperandType());
 9912     if (!VecTy || !isa<ConstantInt, UndefValue>(EI->getIndexOperand()))
 9913       continue;
 9914     std::optional<unsigned> Idx = getExtractIndex(EI);
 9915     // Undefined index.
 9916     if (!Idx) {
 9917       UndefVectorExtracts.push_back(I);
 9918       continue;
 9919     }
 9920     SmallBitVector ExtractMask(VecTy->getNumElements(), true);
 9921     ExtractMask.reset(*Idx);
 9922     if (isUndefVector(EI->getVectorOperand(), ExtractMask).all()) {
 9923       UndefVectorExtracts.push_back(I);
 9924       continue;
 9925     }
 9926     VectorOpToIdx[EI->getVectorOperand()].push_back(I);
 9927   }
 9928   // Sort the vector operands by the maximum number of uses in extractelements.
 9929   MapVector<unsigned, SmallVector<Value *>> VFToVector;
 9930   for (const auto &Data : VectorOpToIdx)
 9931     VFToVector[cast<FixedVectorType>(Data.first->getType())->getNumElements()]
 9932         .push_back(Data.first);
 9933   for (auto &Data : VFToVector) {
 9934     stable_sort(Data.second, [&VectorOpToIdx](Value *V1, Value *V2) {
 9935       return VectorOpToIdx.find(V1)->second.size() >
 9936              VectorOpToIdx.find(V2)->second.size();
 9937     });
 9938   }
 9939   // Find the best pair of the vectors with the same number of elements or a
 9940   // single vector.
 9941   const int UndefSz = UndefVectorExtracts.size();
 9942   unsigned SingleMax = 0;
 9943   Value *SingleVec = nullptr;
 9944   unsigned PairMax = 0;
 9945   std::pair<Value *, Value *> PairVec(nullptr, nullptr);
 9946   for (auto &Data : VFToVector) {
 9947     Value *V1 = Data.second.front();
 9948     if (SingleMax < VectorOpToIdx[V1].size() + UndefSz) {
 9949       SingleMax = VectorOpToIdx[V1].size() + UndefSz;
 9950       SingleVec = V1;
 9951     }
 9952     Value *V2 = nullptr;
 9953     if (Data.second.size() > 1)
 9954       V2 = *std::next(Data.second.begin());
 9955     if (V2 && PairMax < VectorOpToIdx[V1].size() + VectorOpToIdx[V2].size() +
 9956                             UndefSz) {
 9957       PairMax = VectorOpToIdx[V1].size() + VectorOpToIdx[V2].size() + UndefSz;
 9958       PairVec = std::make_pair(V1, V2);
 9959     }
 9960   }
 9961   if (SingleMax == 0 && PairMax == 0 && UndefSz == 0)
 9962     return std::nullopt;
 9963   // Check if better to perform a shuffle of 2 vectors or just of a single
 9964   // vector.
 9965   SmallVector<Value *> SavedVL(VL.begin(), VL.end());
 9966   SmallVector<Value *> GatheredExtracts(
 9967       VL.size(), PoisonValue::get(VL.front()->getType()));
 9968   if (SingleMax >= PairMax && SingleMax) {
 9969     for (int Idx : VectorOpToIdx[SingleVec])
 9970       std::swap(GatheredExtracts[Idx], VL[Idx]);
 9971   } else {
 9972     for (Value *V : {PairVec.first, PairVec.second})
 9973       for (int Idx : VectorOpToIdx[V])
 9974         std::swap(GatheredExtracts[Idx], VL[Idx]);
 9975   }
 9976   // Add extracts from undefs too.
 9977   for (int Idx : UndefVectorExtracts)
 9978     std::swap(GatheredExtracts[Idx], VL[Idx]);
 9979   // Check that gather of extractelements can be represented as just a
 9980   // shuffle of a single/two vectors the scalars are extracted from.
 9981   std::optional<TTI::ShuffleKind> Res =
 9982       isFixedVectorShuffle(GatheredExtracts, Mask);
 9983   if (!Res) {
 9984     // TODO: try to check other subsets if possible.
 9985     // Restore the original VL if attempt was not successful.
 9986     copy(SavedVL, VL.begin());
 9987     return std::nullopt;
 9988   }
 9989   // Restore unused scalars from mask, if some of the extractelements were not
 9990   // selected for shuffle.
 9991   for (int I = 0, E = GatheredExtracts.size(); I < E; ++I) {
 9992     if (Mask[I] == PoisonMaskElem && !isa<PoisonValue>(GatheredExtracts[I]) &&
 9993         isa<UndefValue>(GatheredExtracts[I])) {
 9994       std::swap(VL[I], GatheredExtracts[I]);
 9995       continue;
 9996     }
 9997     auto *EI = dyn_cast<ExtractElementInst>(VL[I]);
 9998     if (!EI || !isa<FixedVectorType>(EI->getVectorOperandType()) ||
 9999         !isa<ConstantInt, UndefValue>(EI->getIndexOperand()) ||
10000         is_contained(UndefVectorExtracts, I))
10001       continue;
10002   }
10003   return Res;
10004 }
