10037 std::optional<TargetTransformInfo::ShuffleKind>
10038 BoUpSLP::isGatherShuffledSingleRegisterEntry(
10039     const TreeEntry *TE, ArrayRef<Value *> VL, MutableArrayRef<int> Mask,
10040     SmallVectorImpl<const TreeEntry *> &Entries, unsigned Part, bool ForOrder) {
10041   Entries.clear();
10042   // TODO: currently checking only for Scalars in the tree entry, need to count
10043   // reused elements too for better cost estimation.
10044   const EdgeInfo &TEUseEI = TE->UserTreeIndices.front();
10045   const Instruction *TEInsertPt = &getLastInstructionInBundle(TEUseEI.UserTE);
10046   const BasicBlock *TEInsertBlock = nullptr;
10047   // Main node of PHI entries keeps the correct order of operands/incoming
10048   // blocks.
10049   if (auto *PHI = dyn_cast<PHINode>(TEUseEI.UserTE->getMainOp())) {
10050     TEInsertBlock = PHI->getIncomingBlock(TEUseEI.EdgeIdx);
10051     TEInsertPt = TEInsertBlock->getTerminator();
10052   } else {
10053     TEInsertBlock = TEInsertPt->getParent();
10054   }
10055   if (!DT->isReachableFromEntry(TEInsertBlock))
10056     return std::nullopt;
10057   auto *NodeUI = DT->getNode(TEInsertBlock);
10058   assert(NodeUI && "Should only process reachable instructions");
10059   SmallPtrSet<Value *, 4> GatheredScalars(VL.begin(), VL.end());
10060   auto CheckOrdering = [&](const Instruction *InsertPt) {
10061     // Argument InsertPt is an instruction where vector code for some other
10062     // tree entry (one that shares one or more scalars with TE) is going to be
10063     // generated. This lambda returns true if insertion point of vector code
10064     // for the TE dominates that point (otherwise dependency is the other way
10065     // around). The other node is not limited to be of a gather kind. Gather
10066     // nodes are not scheduled and their vector code is inserted before their
10067     // first user. If user is PHI, that is supposed to be at the end of a
10068     // predecessor block. Otherwise it is the last instruction among scalars of
10069     // the user node. So, instead of checking dependency between instructions
10070     // themselves, we check dependency between their insertion points for vector
10071     // code (since each scalar instruction ends up as a lane of a vector
10072     // instruction).
10073     const BasicBlock *InsertBlock = InsertPt->getParent();
10074     auto *NodeEUI = DT->getNode(InsertBlock);
10075     if (!NodeEUI)
10076       return false;
10077     assert((NodeUI == NodeEUI) ==
10078                (NodeUI->getDFSNumIn() == NodeEUI->getDFSNumIn()) &&
10079            "Different nodes should have different DFS numbers");
10080     // Check the order of the gather nodes users.
10081     if (TEInsertPt->getParent() != InsertBlock &&
10082         (DT->dominates(NodeUI, NodeEUI) || !DT->dominates(NodeEUI, NodeUI)))
10083       return false;
10084     if (TEInsertPt->getParent() == InsertBlock &&
10085         TEInsertPt->comesBefore(InsertPt))
10086       return false;
10087     return true;
10088   };
